template<class T> using V = vector<T>;

template<class T> using V2 = V<V<T>>;

template<class T> using V3 = V<V2<T>>;



using P = pair<ll,int>;





template<class T>

V<T> VF(V<T> v, function<T(T)> f){

  int n = (int) v.size();

  V<T> ret(n);

  for(int i=0; i<n; ++i) {

    T a = v[i];

    ret[i] = f(a);

  }

  return ret;

}

template<class T, class U>

V<U> VF2(V<T> v, function<U(T)> f){

  int n = (int) v.size();

  V<U> ret(n);

  for(int i=0; i<n; ++i) {

    T a = v[i];

    ret[i] = f(a);

  }

  return ret;

}

template<class T>

void VFS(V<T> &v, function<T(T)> f){

  int n = (int) v.size();

  for(int i=0; i<n; ++i) {

    T a = v[i];

    v[i] = f(a);

  }

  return;

}



constexpr ll mod = 1000000007;



ll modpow(ll a, ll n, ll m) {

	ll res = 1;

	while (n) {

		if (n & 1)res = res * a % m;

		a = a * a%m; n >>= 1;

	}

	return res;

}



void solve(){

  ll n, k; cin >> n >> k;

  ll ans = 0, n2=0, n3=0, k2=0, k3=0;

  n2 = (n*n)%mod;

  n3 = (n2*n) % mod;

  k2 = (k*k) % mod;

  k3 = (k2*k) % mod;

  ans = (n3 + 3*n2 + (-3*k2 + 3*k + 8+1000*mod)*n%mod  + 2*k3 - (6*k2)%mod - (2*k)%mod +12 + 1000*mod ) % mod;

  (ans *= modpow(6,mod-2,mod)) %= mod;

  coutn(ans);

}











